const PG_BASE = {
  host:     process.env.POSTGRES_HOST     || "postgres",
  port:     parseInt(process.env.POSTGRES_PORT || "5432"),
  user:     process.env.POSTGRES_USER     || "postgres",
  password: process.env.POSTGRES_PASSWORD || "postgres",
  client_encoding: "UTF8",
};

const PASSWORD = process.env.SEED_PASSWORD || "Demo1234!";
const MAX_RETRIES = parseInt(process.env.SEED_MAX_RETRIES || "30");
const RETRY_DELAY_MS = parseInt(process.env.SEED_RETRY_DELAY_MS || "5000");

// ─── Utilitários ────────────────────────────────────────────────────────────

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

async function connect(database) {
  const client = new Client({ ...PG_BASE, database });
  await client.connect();
  return client;
}

async function waitForTable(database, table, maxRetries = MAX_RETRIES) {
  for (let i = 1; i <= maxRetries; i++) {
    let client;
    try {
      client = await connect(database);
      const { rows } = await client.query(
        `SELECT 1 FROM information_schema.tables
         WHERE table_schema = 'public' AND table_name = $1`,
        [table]
      );
      if (rows.length > 0) {
        console.log(`  ✓ ${database}.${table} está disponível`);
        return client;
      }
      await client.end();
    } catch (_) {
      if (client) await client.end().catch(() => {});
    }
    console.log(`  ⏳ Aguardando ${database}.${table} (tentativa ${i}/${maxRetries})…`);
    await sleep(RETRY_DELAY_MS);
  }
  throw new Error(`Timeout: ${database}.${table} nunca ficou disponível`);
}

